diff --git a/src/catch2/catch_session.cpp b/src/catch2/catch_session.cpp
index 042b7f4..99d2709 100644
--- a/src/catch2/catch_session.cpp
+++ b/src/catch2/catch_session.cpp
@@ -265,6 +265,26 @@ namespace Catch {
         if( m_configData.libIdentify )
             libIdentify();

+        // Post-parse validation: shard index must be less than shard count
+        if ( m_configData.shardIndex >= m_configData.shardCount ) {
+            config();
+            getCurrentMutableContext().setConfig(m_config.get());
+            auto errStream = makeStream( "%stderr" );
+            auto colour = makeColourImpl( ColourMode::PlatformDefault, errStream.get() );
+            errStream->stream()
+                << colour->guardColour( Colour::Red )
+                << "\nError(s) in input:\n"
+                << TextFlow::Column(
+                       "Shard index (" +
+                       std::to_string( m_configData.shardIndex ) +
+                       ") must be less than shard count (" +
+                       std::to_string( m_configData.shardCount ) + ")" )
+                       .indent( 2 )
+                << "\n\n";
+            errStream->stream() << "Run with -? for usage\n\n" << std::flush;
+            return UnspecifiedErrorExitCode;
+        }
+
         m_config.reset();
         return 0;
     }
